css:
* { margin: 0; padding: 0; box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; }
body { background: #0a0e1a; color: white; }
.layout { display: flex; min-height: 100vh; }
.sidebar { width: 220px; background: #0f1320; border-right: 1px solid rgba(255,255,255,0.06); padding: 28px 18px; flex-shrink: 0; }
.logo { font-size: 18px; font-weight: 800; margin-bottom: 32px; padding-left: 8px; }
nav { display: flex; flex-direction: column; gap: 4px; }
nav a { display: flex; align-items: center; gap: 12px; padding: 11px 12px; border-radius: 10px; color: rgba(255,255,255,0.5); font-size: 14px; font-weight: 600; cursor: pointer; text-decoration: none; }
nav a span { font-size: 16px; }
nav a.active { background: rgba(236,72,153,0.12); color: #f472b6; }
.content { flex: 1; padding: 32px 36px; max-width: 1100px; }
header { display: flex; justify-content: space-between; align-items: flex-end; margin-bottom: 26px; flex-wrap: wrap; gap: 12px; }
header h1 { font-size: 26px; font-weight: 800; }
header p { color: rgba(255,255,255,0.4); font-size: 13px; margin-top: 4px; }
.new-post { background: linear-gradient(135deg, #ec4899, #be185d); border: none; color: white; padding: 12px 22px; border-radius: 12px; font-size: 13.5px; font-weight: 700; cursor: pointer; box-shadow: 0 10px 25px rgba(236,72,153,0.3); }
.stats { display: grid; grid-template-columns: repeat(auto-fit, minmax(180px, 1fr)); gap: 14px; margin-bottom: 22px; }
.stat { background: rgba(255,255,255,0.03); border: 1px solid rgba(255,255,255,0.07); border-radius: 16px; padding: 18px 20px; display: flex; align-items: center; gap: 12px; position: relative; }
.stat .icon { font-size: 22px; }
.stat .value { display: block; font-size: 20px; font-weight: 800; }
.stat .label { display: block; color: rgba(255,255,255,0.4); font-size: 12px; font-weight: 600; }
.delta { position: absolute; top: 16px; right: 16px; font-size: 11px; font-weight: 700; padding: 2px 8px; border-radius: 999px; }
.delta.up { color: #4ade80; background: rgba(74,222,128,0.12); }
.delta.down { color: #f87171; background: rgba(248,113,113,0.12); }
.grid { display: grid; grid-template-columns: 1.4fr 1fr; gap: 16px; margin-bottom: 16px; }
.panel { background: rgba(255,255,255,0.03); border: 1px solid rgba(255,255,255,0.07); border-radius: 18px; padding: 22px; }
.panel-head { display: flex; justify-content: space-between; align-items: center; margin-bottom: 18px; }
.panel-head h2 { font-size: 15px; font-weight: 700; }
.badge { background: rgba(236,72,153,0.12); color: #f472b6; font-size: 11px; font-weight: 700; padding: 4px 10px; border-radius: 999px; }
.bars { display: flex; align-items: flex-end; gap: 10px; height: 140px; }
.bar { flex: 1; background: rgba(255,255,255,0.08); border-radius: 8px 8px 0 0; cursor: pointer; }
.bar.active { background: linear-gradient(180deg, #f472b6, #ec4899); }
.bar-labels { display: flex; gap: 10px; margin-top: 10px; }
.bar-labels span { flex: 1; text-align: center; font-size: 11px; color: rgba(255,255,255,0.35); }
.platform { display: flex; align-items: center; gap: 12px; margin-bottom: 16px; }
.platform:last-child { margin-bottom: 0; }
.pname { font-size: 13px; font-weight: 600; width: 110px; flex-shrink: 0; }
.track { flex: 1; height: 8px; background: rgba(255,255,255,0.06); border-radius: 999px; overflow: hidden; }
.fill { height: 100%; border-radius: 999px; }
.pval { font-size: 12px; font-weight: 700; color: rgba(255,255,255,0.6); width: 36px; text-align: right; }
.posts { display: grid; grid-template-columns: repeat(auto-fit, minmax(180px, 1fr)); gap: 14px; }
.post-card { background: rgba(255,255,255,0.03); border: 1px solid rgba(255,255,255,0.06); border-radius: 14px; padding: 16px; }
.post-thumb { font-size: 30px; margin-bottom: 10px; }
.post-text { font-size: 13px; color: rgba(255,255,255,0.7); margin-bottom: 12px; line-height: 1.5; }
.post-stats { display: flex; gap: 12px; font-size: 12px; color: rgba(255,255,255,0.4); }
@media (max-width: 800px) { .layout { flex-direction: column; } .sidebar { width: 100%; display: flex; } nav { flex-direction: row; overflow-x: auto; } .grid { grid-template-columns: 1fr; } }

